import{_ as a,o as s,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Practice Sessions","description":"","frontmatter":{},"headers":[],"relativePath":"practice/index.md","filePath":"practice/index.md"}'),r={name:"practice/index.md"};function n(o,e,c,l,d,p){return s(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="practice-sessions" tabindex="-1">Practice Sessions <a class="header-anchor" href="#practice-sessions" aria-label="Permalink to &quot;Practice Sessions&quot;">​</a></h1><p>Diamond Analytics supports two practice session types: Team Practice and Individual Practice. Practice data flows into the same analytics as game data and can be filtered separately using the event type filter.</p><h2 id="session-types" tabindex="-1">Session Types <a class="header-anchor" href="#session-types" aria-label="Permalink to &quot;Session Types&quot;">​</a></h2><p><strong>Team Practice</strong> — whole-team practice. Use this for bullpen sessions, batting practice, fielding drills, and intra-squad work. Multiple players are tracked in the same session.</p><p><strong>Individual Practice</strong> — focused work with one player. Used for mechanics assessments, targeted skill development, and one-on-one coaching sessions. This is where mechanics assessments are conducted.</p><h2 id="starting-a-practice-session" tabindex="-1">Starting a Practice Session <a class="header-anchor" href="#starting-a-practice-session" aria-label="Permalink to &quot;Starting a Practice Session&quot;">​</a></h2><ol><li>From the dashboard tap <strong>Log Practice Data</strong></li><li>Select <strong>Team Practice</strong> or <strong>Individual Practice</strong></li><li>For Individual Practice select the player</li><li>Tap <strong>Start Session</strong></li></ol><p>The Practice Hub opens with the same four loggers available as in Game mode.</p><h2 id="key-differences-from-game-mode" tabindex="-1">Key Differences from Game Mode <a class="header-anchor" href="#key-differences-from-game-mode" aria-label="Permalink to &quot;Key Differences from Game Mode&quot;">​</a></h2><ul><li>No opponent or score tracker</li><li>No inning tracker</li><li>No game result to record at the end</li><li>Individual Practice includes the Mechanics Assessment logger</li></ul><h2 id="ending-a-practice-session" tabindex="-1">Ending a Practice Session <a class="header-anchor" href="#ending-a-practice-session" aria-label="Permalink to &quot;Ending a Practice Session&quot;">​</a></h2><p>Tap <strong>End Session</strong> from the Practice Hub. You are not required to record a result — just confirm you want to end the session.</p><p>Practice sessions appear in the session history with the date and duration. Data from all practice sessions is included in analytics (with the event type filter set to All or Team/Individual Practice).</p>',13)])])}const u=a(r,[["render",n]]);export{m as __pageData,u as default};
